package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnCommentApproveProxy struct {
	automation.UnimplementedOnCommentApproveServer
	client automation.OnCommentApproveClient
}

func init() {
	proxyutil.Register(&automation.OnCommentApprove_ServiceDesc, NewOnCommentApproveProxy)
}
func NewOnCommentApproveProxy(cc grpc.ClientConnInterface) automation.OnCommentApproveServer {
	return &OnCommentApproveProxy{client: automation.NewOnCommentApproveClient(cc)}
}
func (p *OnCommentApproveProxy) OnCommentApprove(ctx context.Context, in *events.CommentApprove) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.CommentApprove, automation.HandlerResult](p.client.OnCommentApprove)(ctx, in)
}
